  // 1. Calculate end-effector position
  const endEffector = forwardKinematics({ angles, lengths: ARM_LENGTHS });

  // 2. Target accuracy (Euclidean distance)
  const distance = Math.sqrt(
    Math.pow(endEffector.x - target.x, 2) +
    Math.pow(endEffector.y - target.y, 2)
  );

  // 3. Motion efficiency (angular change penalty)
  let motionCost = 0;
  for (let i = 0; i < angles.length; i++) {
    const diff = angles[i] - currentAngles[i];
    motionCost += Math.abs(diff);
  }

  // 4. Collision penalty
  let collisionPenalty = 0;
  const segments = getArmSegments(angles);

  for (const segment of segments) {
    for (const obstacle of obstacles) {
      if (detectCollision(segment, obstacle)) {
        collisionPenalty += 2000; // High penalty for collision
      }
    }
  }

  // Weighted sum
  return ALPHA * distance + BETA * motionCost + GAMMA * collisionPenalty;
